import { API_URL } from '../config.js';

const FILES_ROOT = `${API_URL}/api/files`;

export const IMAGE_SCOPES = ['food', 'meal', 'ai'] as const;
export type ImageScope = typeof IMAGE_SCOPES[number];

export interface UploadImageResponse {
    /** Directory key (e.g. 'images/food/<uuidv7>'); append /display.jpg or /original.<ext>. */
    image_path: string;
}

export class FilesService {
    /**
     * Upload a single image via multipart/form-data. Story 124 — the server
     * keeps the original bytes and produces a progressive display.jpg.
     */
    static async uploadImage(scope: ImageScope, blob: Blob, filename = 'photo'): Promise<UploadImageResponse> {
        const form = new FormData();
        form.set('image', blob, filename);
        const response = await fetch(`${FILES_ROOT}/images?scope=${encodeURIComponent(scope)}`, {
            method: 'POST',
            body: form,
        });
        if (!response.ok) {
            const data = await response.json().catch(() => ({})) as { error?: string };
            throw new Error(data.error ?? `Image upload failed: ${response.statusText}`);
        }
        return response.json();
    }

    /** Absolute URL for a specific variant of a stored image. */
    static variantUrl(imagePath: string, variant: 'display.jpg' | 'original.jpg' | 'original.jpeg' | 'original.png' | 'original.webp'): string {
        return `${API_URL}/api/files/${imagePath}/${variant}`;
    }
}
